namespace sv_fae8ea2223824d10a8e74c2a7041d9b3.Models;

public sealed class Recipe
{
    public required int Id { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public required int PrepTimeMinutes { get; init; }
}

using sv_fae8ea2223824d10a8e74c2a7041d9b3.Models;

namespace sv_fae8ea2223824d10a8e74c2a7041d9b3.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_fae8ea2223824d10a8e74c2a7041d9b3.Models;

namespace sv_fae8ea2223824d10a8e74c2a7041d9b3.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Spaghetti Carbonara", Description = "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Margherita Pizza", Description = "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", PrepTimeMinutes = 45 },
            new() { Id = 3, Title = "Risotto alla Milanese", Description = "Creamy saffron-infused risotto from Milan.", PrepTimeMinutes = 40 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Chicken Tikka Masala", Description = "Tender chicken in a creamy, spiced tomato sauce.", PrepTimeMinutes = 50 },
            new() { Id = 5, Title = "Palak Paneer", Description = "Fresh paneer cubes in a smooth, seasoned spinach gravy.", PrepTimeMinutes = 35 },
            new() { Id = 6, Title = "Biryani", Description = "Fragrant basmati rice layered with spiced meat and caramelized onions.", PrepTimeMinutes = 90 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Spit-grilled pork tacos with pineapple, cilantro, and onion.", PrepTimeMinutes = 60 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Enchiladas Verdes", Description = "Corn tortillas filled with chicken, topped with tangy tomatillo salsa.", PrepTimeMinutes = 45 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow backend API call.
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

