arguments.file_text:
@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_fae8ea2223824d10a8e74c2a7041d9b3.Models
@using sv_fae8ea2223824d10a8e74c2a7041d9b3.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<div class="mb-3">
    <a href="/recipes/1?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 1 ? "active" : "")">Italian</a>
    <a href="/recipes/2?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 2 ? "active" : "")">Indian</a>
    <a href="/recipes/3?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 3 ? "active" : "")">Mexican</a>
</div>

<div class="mb-3">
    <span class="me-2">Sort by:</span>
    <a href="/recipes/@CuisineId?sort=newest" class="btn btn-sm btn-outline-secondary @(Sort == "newest" ? "active" : "")">Newest</a>
    <a href="/recipes/@CuisineId?sort=popular" class="btn btn-sm btn-outline-secondary @(Sort == "popular" ? "active" : "")">Popular</a>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@errorMessage</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (isRefreshing)
    {
        <div class="alert alert-info py-1 px-3" role="status">Refreshing…</div>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in GetSortedRecipes())
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? recipes;
    private string? errorMessage;
    private bool isRefreshing;
    private int loadedCuisineId;

    private CancellationTokenSource? loadCts;

