+@page "/recipes/{CuisineId:int}"
+@rendermode InteractiveServer
+@using sv_fae8ea2223824d10a8e74c2a7041d9b3.Models
+@using sv_fae8ea2223824d10a8e74c2a7041d9b3.Services
+@inject IRecipeService RecipeService
+@inject ILogger<Recipes> Logger
+@implements IDisposable
+
+<PageTitle>Recipes</PageTitle>
+
+<h1>Recipes</h1>
+
+<div class="mb-3">
+    <a href="/recipes/1?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 1 ? "active" : "")">Italian</a>
+    <a href="/recipes/2?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 2 ? "active" : "")">Indian</a>
+    <a href="/recipes/3?sort=@Sort" class="btn btn-outline-primary @(CuisineId == 3 ? "active" : "")">Mexican</a>
+</div>
+
+<div class="mb-3">
+    <span class="me-2">Sort by:</span>
+    <a href="/recipes/@CuisineId?sort=newest" class="btn btn-sm btn-outline-secondary @(Sort == "newest" ? "active" : "")">Newest</a>
+    <a href="/recipes/@CuisineId?sort=popular" class="btn btn-sm btn-outline-secondary @(Sort == "popular" ? "active" : "")">Popular</a>
+</div>
+
+@if (errorMessage is not null)
+{
+    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
+        <span>@errorMessage</span>
+        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
+    </div>
+}
+else if (recipes is null)
+{
+    <p><em>Loading recipes…</em></p>
+}
+else
+{
+    @if (isRefreshing)
+    {
+        <div class="alert alert-info py-1 px-3" role="status">Refreshing…</div>
+    }
+
+    <table class="table">
+        <thead>
+            <tr>
+                <th>Title</th>
+                <th>Description</th>
+                <th>Prep Time (min)</th>
+            </tr>
+        </thead>
+        <tbody>
+            @foreach (var recipe in GetSortedRecipes())
+            {
+                <tr>
+                    <td>@recipe.Title</td>
+                    <td>@recipe.Description</td>
+                    <td>@recipe.PrepTimeMinutes</td>
+                </tr>
+            }
+        </tbody>
+    </table>
+}
+
+@code {
+    [Parameter]
+    public int CuisineId { get; set; }
+
+    [SupplyParameterFromQuery(Name = "sort")]
+    public string? Sort { get; set; }
+
+    private List<Recipe>? recipes;
+    private string? errorMessage;
+    private bool isRefreshing;
+    private int loadedCuisineId;
+
+    private CancellationTokenSource? loadCts;
+
+    protected override async Task OnParametersSetAsync()
+    {
+        // Only reload when the cuisine actually changes.
+        if (loadedCuisineId == CuisineId && recipes is not null)
+        {
+            return;
+        }
+
+        await LoadRecipesAsync();
+    }
+
+    private async Task LoadRecipesAsync()
+    {
+        // Cancel any in-flight request for a previous cuisine.
+        await CancelPendingLoadAsync();
+
+        loadedCuisineId = CuisineId;
+        errorMessage = null;
+        isRefreshing = recipes is not null;
+        loadCts = new CancellationTokenSource();
+        var token = loadCts.Token;
+
+        try
+        {
+            var result = await RecipeService.GetByCuisineAsync(CuisineId, token);
+
+            // Guard against a stale callback after cancellation.
+            if (token.IsCancellationRequested)
+            {
+                return;
+            }
+
+            recipes = result;
+            isRefreshing = false;
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected when the user navigated away or switched cuisine — nothing to do.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
+            errorMessage = "The request timed out. Please try again.";
+            isRefreshing = false;
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
+            errorMessage = "Something went wrong while loading recipes. Please try again.";
+            isRefreshing = false;
+        }
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadRecipesAsync();
+    }
+
+    private IEnumerable<Recipe> GetSortedRecipes()
+    {
+        if (recipes is null) return Enumerable.Empty<Recipe>();
+
+        return Sort?.ToLowerInvariant() switch
+        {
+            "popular" => recipes.OrderBy(r => r.PrepTimeMinutes),
+            _ => recipes.OrderByDescending(r => r.Id),
+        };
+    }
+
+    private async Task CancelPendingLoadAsync()
+    {
+        if (loadCts is not null)
+        {
+            await loadCts.CancelAsync();
+            loadCts.Dispose();
+            loadCts = null;
+        }
+    }
+
+    public void Dispose()
+    {
+        loadCts?.Cancel();
+        loadCts?.Dispose();
+        loadCts = null;
+    }
+}
+

